def solve(*args):
    # Implementing the functionality to manage terms of use
    terms_of_use = []

    def add_term(term):
        terms_of_use.append(term)

    def get_terms():
        return terms_of_use

    def remove_term(term):
        if term in terms_of_use:
            terms_of_use.remove(term)

    # Assuming args will contain commands and terms
    for arg in args:
        command, *term = arg.split()
        if command == "add":
            add_term(" ".join(term))
        elif command == "remove":
            remove_term(" ".join(term))

    return get_terms()
